mapper.select:
SELECT * FROM biz_house 
WHERE deleted = 0 AND status = #{status}

    AND city = #{city}


    AND district = #{district}


    AND house_type LIKE CONCAT('%', #{houseType}, '%')


    AND rent_price >= #{minPrice}


    AND rent_price <= #{maxPrice}


    AND area >= #{minArea}


    AND area <= #{maxArea}


    AND rent_way = #{rentWay}
